//! Regenerate the committed self-inspection artifacts.
//!
//! `data/meta/self-ast.lino` and `data/meta/self-healing-case.lino` are censuses
//! of real source files, so any refactor that moves code between modules makes
//! them stale and the issue #538 / #558 regressions fail. They are committed on
//! purpose — the point is that the census is reviewable — so the fix is to
//! regenerate rather than to relax the assertion. Run with:
//!
//! ```sh
//! cargo run --example regen_committed_artifacts --all-features
//! ```
fn main() {
    std::fs::write("data/meta/self-ast.lino", formal_ai::agentic_coding::self_ast::render_document())
        .expect("write self-ast.lino");
    println!("regenerated data/meta/self-ast.lino");
}
EOF
